const body = $input.first().json.body || $input.first().json;
const doc = body.numero_documento || '';
const pcr = body.numero_pcr || '';
const forn = body.fornecedor_codigo || '';

// Montar filtros para busca
const filters = [];
if (doc) filters.push(`numero_documento=eq.${doc}`);
if (pcr) filters.push(`numero_pcr=eq.${pcr}`);

return [{ json: { doc, pcr, forn, filter: filters.join('&') } }];

const existentes = $input.all();
const original = $('Preparar Filtros').first().json;

if (existentes.length > 0 && existentes[0].json.id) {
  // DUPLICADO ENCONTRADO
  const dup = existentes[0].json;
  return [{
    json: {
      duplicado: true,
      mensagem: `Documento já existe: ${dup.numero_documento || dup.numero_pcr} (ID: ${dup.id}, criado em: ${dup.criado_em})`,
      registro_existente: dup,
      tipo_divergencia: 'duplicidade_carga',
      gravidade: 'atencao',
      status: 'aberta',
      tabela_origem: 'atak_cargas_raw',
      registro_origem_id: dup.id,
      fornecedor_codigo: original.forn,
      numero_documento: original.doc || original.pcr,
      campo_divergente: 'numero_documento/numero_pcr',
      valor_esperado: 'Registro único',
      valor_encontrado: `Duplicata de ${dup.id}`,
      detectado_por: 'n8n_webhook_dedup'
    }
  }];
} else {
  return [{
    json: {
      duplicado: false,
      mensagem: 'Documento não encontrado. Pode prosseguir com inserção.'
    }
  }];
}
